    /// [51] Wenn die Marktlokations-ID im SG8 RFF+Z18 derselben SG8 SEQ+Z98 (Informative Daten der Marktlokation) mit derselben Zeitraum-ID im DE1050 nicht auf ein SG8 SEQ+Z78 (Referenz auf die Lokationsbünde...
    // REVIEW: Cross-SG condition: checks that SG8 SEQ+Z98 groups (Daten der Marktlokation) do NOT share a Zeitraum-ID with SG8 SEQ+Z78 groups (Lokationsbündelstruktur) that carry the 'Verbrauch ohne Messlokation (Pauschal)' code 9992 00000 001 8 in RFF+Z31. Medium confidence due to the multi-step cross-group correlation logic and the whitespace-normalized code comparison. (medium confidence)
    fn evaluate_51(&self, ctx: &EvaluationContext) -> ConditionResult {
        let nav = match ctx.navigator() {
            Some(n) => n,
            None => return ConditionResult::Unknown,
        };
        let sg8_count = nav.group_instance_count(&["SG4", "SG8"]);

        // Step 1: Collect Zeitraum-IDs from Z78 SG8 groups that have RFF+Z31 with the target code
        let target_code = "9992000000018";
        let mut z78_zeitraum_ids: std::collections::HashSet<String> =
            std::collections::HashSet::new();
        for i in 0..sg8_count {
            let seq_segs = nav.find_segments_in_group("SEQ", &["SG4", "SG8"], i);
            let is_z78 = seq_segs.iter().any(|s| {
                s.elements
                    .first()
                    .and_then(|e| e.first())
                    .is_some_and(|v| v == "Z78")
            });
            if !is_z78 {
                continue;
            }
            let rff_segs = nav.find_segments_in_group("RFF", &["SG4", "SG8"], i);
            let has_z31_target = rff_segs.iter().any(|s| {
                s.elements
                    .first()
                    .and_then(|e| e.first())
                    .is_some_and(|v| v == "Z31")
                    && s.elements
                        .first()
                        .and_then(|e| e.get(1))
                        .is_some_and(|v| v.replace(' ', "") == target_code)
            });
            if has_z31_target {
                for seq in &seq_segs {
                    if seq
                        .elements
                        .first()
                        .and_then(|e| e.first())
                        .is_some_and(|v| v == "Z78")
                    {
                        if let Some(zeit_id) = seq.elements.get(1).and_then(|e| e.first()) {
                            if !zeit_id.is_empty() {
                                z78_zeitraum_ids.insert(zeit_id.clone());
                            }
                        }
                    }
                }
            }
        }

        if z78_zeitraum_ids.is_empty() {
            // No Z78 with the target code exists — the Z98 group cannot reference it, condition True
            return ConditionResult::True;
        }

        // Step 2: Check if any Z98 SG8 shares a Zeitraum-ID with a target Z78 SG8
        for i in 0..sg8_count {
            let seq_segs = nav.find_segments_in_group("SEQ", &["SG4", "SG8"], i);
            for seq in &seq_segs {
                if seq
                    .elements
                    .first()
                    .and_then(|e| e.first())
                    .is_some_and(|v| v == "Z98")
                {
                    if let Some(zeit_id) = seq.elements.get(1).and_then(|e| e.first()) {
                        if z78_zeitraum_ids.contains(zeit_id) {
                            // Z98 SG8 references a Z78 with the Pauschal code — condition False
                            return ConditionResult::False;
                        }
                    }
                }
            }
        }
        ConditionResult::True
    }

