    /// [134] Wenn dieses DTM+Z25 (Verwendung der Daten ab) nicht im SG6 RFF+Z48/ Z55 (Verwendungszeitraum der Daten: Erwartete Daten/ Keine Daten erwartet) mit der Zeitraum ID "1" im DE1156 ist, muss das Datum ...
    // REVIEW: Temporal consistency check across SG6 Verwendungszeitraum slices with RFF+Z48/Z55 (Erwartete Daten / Keine Daten erwartet). For each slice with Zeitraum-ID > 1, its DTM+Z25 (Daten ab) must equal DTM+Z26 (Daten bis) of the next-lower Zeitraum-ID slice. Reads DE1156 (elements[0][2]) for the Zeitraum-ID, sorts numerically, then validates continuity. Medium confidence due to ordering semantics and implicit 'current SG6 context' requirement. (medium confidence)
    fn evaluate_134(&self, ctx: &EvaluationContext) -> ConditionResult {
        let nav = match ctx.navigator() {
            Some(n) => n,
            None => return ConditionResult::Unknown,
        };
        let sg6_count = nav.group_instance_count(&["SG4", "SG6"]);

        // Collect (zeitraum_id_numeric, dtm_z25_value, dtm_z26_value) for SG6 groups with RFF+Z48 or RFF+Z55
        let mut slices: Vec<(i64, String, String)> = Vec::new();
        for i in 0..sg6_count {
            let rff_segs = nav.find_segments_in_group("RFF", &["SG4", "SG6"], i);
            // DE1156 is elements[0][2] for RFF Verwendungszeitraum
            let zeitraum_id = rff_segs.iter().find_map(|s| {
                let qual = s.elements.first().and_then(|e| e.first())?;
                if qual == "Z48" || qual == "Z55" {
                    let id = s.elements.first().and_then(|e| e.get(2))?;
                    if !id.is_empty() {
                        Some(id.clone())
                    } else {
                        None
                    }
                } else {
                    None
                }
            });
            let Some(zid_str) = zeitraum_id else { continue };
            let Ok(zid_num) = zid_str.parse::<i64>() else {
                continue;
            };
            let dtm_segs = nav.find_segments_in_group("DTM", &["SG4", "SG6"], i);
            let z25 = dtm_segs
                .iter()
                .find_map(|s| {
                    if s.elements
                        .first()
                        .and_then(|e| e.first())
                        .is_some_and(|v| v == "Z25")
                    {
                        s.elements.first().and_then(|e| e.get(1)).cloned()
                    } else {
                        None
                    }
                })
                .unwrap_or_default();
            let z26 = dtm_segs
                .iter()
                .find_map(|s| {
                    if s.elements
                        .first()
                        .and_then(|e| e.first())
                        .is_some_and(|v| v == "Z26")
                    {
                        s.elements.first().and_then(|e| e.get(1)).cloned()
                    } else {
                        None
                    }
                })
                .unwrap_or_default();
            slices.push((zid_num, z25, z26));
        }
        if slices.len() < 2 {
            return ConditionResult::Unknown;
        }
        slices.sort_by_key(|s| s.0);
        // For each slice with Zeitraum-ID != 1, DTM+Z25 must equal DTM+Z26 of the immediately preceding slice
        for idx in 1..slices.len() {
            let (id, z25, _) = &slices[idx];
            let (_, _, prev_z26) = &slices[idx - 1];
            if *id != 1 && !z25.is_empty() && !prev_z26.is_empty() && z25 != prev_z26 {
                return ConditionResult::False;
            }
        }
        ConditionResult::True
    }

