    /// [387] Wenn in derselben SG8 (OBIS-Daten der Marktlokation) eine OBIS-Kennzahl für Energiemenge im PIA+5 vorhanden und es sich lt. Codeliste OBIS um eine OBIS mit zugeordneter Zählzeit handelt (Tarif: e...
    // REVIEW: Iterates SG8 instances that are OBIS-Daten der Marktlokation (SEQ+Z02/ZA1/ZA2/ZE3), then for each finds PIA+5 and parses the OBIS string to extract the E value (Tarif/Zählzeit field at index 2 after splitting C.D.E by '.'). Returns True if E is in range 1–62, indicating a Zählzeit-differentiated (tariff-associated) OBIS. Medium confidence because the 'Energiemenge' semantic (C value should indicate energy quantity) is not fully validated — only the E=1..62 Zählzeit criterion stated in the condition text is checked. (medium confidence)
    fn evaluate_387(&self, ctx: &EvaluationContext) -> ConditionResult {
        let nav = match ctx.navigator() {
            Some(n) => n,
            None => return ConditionResult::Unknown,
        };
        let sg8_count = nav.group_instance_count(&["SG4", "SG8"]);
        for i in 0..sg8_count {
            let seq_segs = nav.find_segments_in_group("SEQ", &["SG4", "SG8"], i);
            let is_obis_malo = seq_segs.iter().any(|s| {
                s.elements
                    .first()
                    .and_then(|e| e.first())
                    .is_some_and(|v| matches!(v.as_str(), "Z02" | "ZA1" | "ZA2" | "ZE3"))
            });
            if !is_obis_malo {
                continue;
            }
            let pia_segs = nav.find_segments_in_group("PIA", &["SG4", "SG8"], i);
            for pia in &pia_segs {
                if !pia
                    .elements
                    .first()
                    .and_then(|e| e.first())
                    .is_some_and(|v| v == "5")
                {
                    continue;
                }
                let obis = match pia.elements.get(1).and_then(|e| e.first()) {
                    Some(o) => o.as_str(),
                    None => continue,
                };
                // OBIS format: A-B:C.D.E*F — extract E (Tarif/Zählzeit) as split('.')[2] after ':'
                let after_colon = obis.find(':').map(|p| &obis[p + 1..]).unwrap_or(obis);
                let parts: Vec<&str> = after_colon.split('.').collect();
                if parts.len() >= 3 {
                    let e_str = parts[2].split('*').next().unwrap_or("");
                    if let Ok(e_val) = e_str.parse::<u32>() {
                        if e_val >= 1 && e_val <= 62 {
                            return ConditionResult::True;
                        }
                    }
                }
            }
        }
        ConditionResult::False
    }

