    // REVIEW: Condition 2011 requires the group to appear exactly once for each Zeitraum-ID from DE1156 of SG6 RFF+Z49/Z53 (Verwendungszeitraum 'Gültige Daten'/'Keine Daten') as referenced by the request message (via SG6 RFF+TN). Implementation collects DE1156 values (elements[0][2]) from SG6 RFF with Z49 or Z53 qualifiers. Returns True when qualifying Zeitraum-IDs are found (indicating the group should exist). Medium confidence because the 'aus der Anfragenachricht' cross-message reference cannot be fully verified within a single message context. (medium confidence)
    fn evaluate_2011(&self, ctx: &EvaluationContext) -> ConditionResult {
        let nav = match ctx.navigator() {
            Some(n) => n,
            None => {
                // Fallback: check message-wide RFF+Z49/Z53 for DE1156 Zeitraum-IDs
                let rff_segs = ctx.find_segments("RFF");
                let has_qualifying = rff_segs.iter().any(|s| {
                    let qual = s
                        .elements
                        .first()
                        .and_then(|e| e.first())
                        .map(|v| v.as_str());
                    matches!(qual, Some("Z49") | Some("Z53"))
                        && s.elements
                            .first()
                            .and_then(|e| e.get(2))
                            .is_some_and(|v| !v.is_empty())
                });
                return if has_qualifying {
                    ConditionResult::True
                } else {
                    ConditionResult::Unknown
                };
            }
        };
        let sg6_count = nav.group_instance_count(&["SG4", "SG6"]);
        let mut zeitraum_ids: std::collections::HashSet<String> = std::collections::HashSet::new();
        for i in 0..sg6_count {
            let rff_segs = nav.find_segments_in_group("RFF", &["SG4", "SG6"], i);
            for rff in &rff_segs {
                let qual = rff
                    .elements
                    .first()
                    .and_then(|e| e.first())
                    .map(|s| s.as_str());
                if matches!(qual, Some("Z49") | Some("Z53")) {
                    // DE1156 is elements[0][2]
                    if let Some(zeitraum_id) = rff.elements.first().and_then(|e| e.get(2)) {
                        if !zeitraum_id.is_empty() {
                            zeitraum_ids.insert(zeitraum_id.clone());
                        }
                    }
                }
            }
        }
        if zeitraum_ids.is_empty() {
            return ConditionResult::Unknown;
        }
        // The segment group should appear exactly once per distinct Zeitraum-ID from SG6 RFF+Z49/Z53
        // We verify that qualifying Zeitraum-IDs are present — cardinality enforcement is structural
        ConditionResult::True
    }

