    /// [50] Wenn kein SG8 SEQ+ZE7 (Informative Daten der Tranche) mit derselben Zeitraum-ID im DE1050 auf die gleiche Marktlokation-ID mit dem RFF+Z18 (Marktlokation) referenziert wie dieses SG8 SEQ+Z98 (Infor...
    // REVIEW: Collects (Zeitraum-ID from SEQ.elements[1][0], Marktlok-ID from sibling RFF+Z18.elements[0][1]) for all SG8 instances with SEQ+Z98 and SEQ+ZE7. Returns True if any Z98 group has no ZE7 group matching on both values. Uses collect_group_values with instance-index correlation via HashMap, assuming each SG8 has at most one SEQ (guaranteed as entry segment) and the zip ordering is stable. (medium confidence)
    fn evaluate_50(&self, ctx: &EvaluationContext) -> ConditionResult {
        use std::collections::HashMap;

        let seq_quals = ctx.collect_group_values("SEQ", 0, 0, &["SG4", "SG8"]);
        let seq_zeitraum = ctx.collect_group_values("SEQ", 1, 0, &["SG4", "SG8"]);
        let rff_quals = ctx.collect_group_values("RFF", 0, 0, &["SG4", "SG8"]);
        let rff_ids = ctx.collect_group_values("RFF", 0, 1, &["SG4", "SG8"]);

        // Build per-instance RFF lookup: instance_idx -> list of (qualifier, id)
        let mut rff_by_instance: HashMap<usize, Vec<(String, String)>> = HashMap::new();
        for ((idx, q), (_, id)) in rff_quals.iter().zip(rff_ids.iter()) {
            rff_by_instance
                .entry(*idx)
                .or_default()
                .push((q.clone(), id.clone()));
        }

        // Build (zeitraum_id, marktlok_id) for Z98 and ZE7 SG8 instances
        let mut seq_zeitraum_map: HashMap<usize, String> = HashMap::new();
        for (idx, z) in &seq_zeitraum {
            seq_zeitraum_map.insert(*idx, z.clone());
        }

        let z98_data: Vec<(String, String)> = seq_quals
            .iter()
            .filter(|(_, q)| q == "Z98")
            .map(|(idx, _)| {
                let zeitraum = seq_zeitraum_map.get(idx).cloned().unwrap_or_default();
                let marktlok = rff_by_instance
                    .get(idx)
                    .and_then(|rffs| rffs.iter().find(|(q, _)| q == "Z18"))
                    .map(|(_, id)| id.clone())
                    .unwrap_or_default();
                (zeitraum, marktlok)
            })
            .collect();

        if z98_data.is_empty() {
            return ConditionResult::Unknown;
        }

        let ze7_data: Vec<(String, String)> = seq_quals
            .iter()
            .filter(|(_, q)| q == "ZE7")
            .map(|(idx, _)| {
                let zeitraum = seq_zeitraum_map.get(idx).cloned().unwrap_or_default();
                let marktlok = rff_by_instance
                    .get(idx)
                    .and_then(|rffs| rffs.iter().find(|(q, _)| q == "Z18"))
                    .map(|(_, id)| id.clone())
                    .unwrap_or_default();
                (zeitraum, marktlok)
            })
            .collect();

        ConditionResult::from(z98_data.iter().any(|(z98_zeit, z98_lok)| {
            !ze7_data
                .iter()
                .any(|(ze7_zeit, ze7_lok)| ze7_zeit == z98_zeit && ze7_lok == z98_lok)
        }))
    }

