    /// [62] Wenn mehr als eine SG8 SEQ+Z45 (Netznutzungsabrechnungsdaten der Marktlokation), mit derselben Zeitraum-ID im DE1050, mit einer Gruppen-/Artikel-ID im SG8 PIA+Z02 (Gruppenartikel-ID / Artikel-ID), ...
    // REVIEW: Iterates SG8 instances within each SG4, finds those with SEQ+Z45 and a non-empty Zeitraum-ID in elements[1][0]. Checks if PIA+Z02 in the same SG8 has a product code (elements[1][0]) beginning with 1-08-1 through 1-08-5. Groups by Zeitraum-ID and checks if any ID appears more than once. Requires navigator for per-instance group segment access; returns Unknown without one. (medium confidence)
    fn evaluate_62(&self, ctx: &EvaluationContext) -> ConditionResult {
        let nav = match ctx.navigator {
            Some(n) => n,
            None => return ConditionResult::Unknown,
        };
        use std::collections::HashMap;
        let mut count_by_zid: HashMap<String, u32> = HashMap::new();
        let sg4_count = nav.group_instance_count(&["SG4"]);
        for sg4_idx in 0..sg4_count {
            let sg8_count = nav.child_group_instance_count(&["SG4"], sg4_idx, "SG8");
            for sg8_idx in 0..sg8_count {
                let seqs =
                    nav.find_segments_in_child_group("SEQ", &["SG4"], sg4_idx, "SG8", sg8_idx);
                let zeitraum_opt = seqs
                    .iter()
                    .filter(|s| {
                        s.elements
                            .first()
                            .and_then(|e: &Vec<String>| e.first())
                            .is_some_and(|v: &String| v == "Z45")
                    })
                    .filter_map(|s| {
                        s.elements
                            .get(1)
                            .and_then(|e: &Vec<String>| e.first())
                            .filter(|v| !v.is_empty())
                            .cloned()
                    })
                    .next();
                let Some(zid) = zeitraum_opt else { continue };
                let pias =
                    nav.find_segments_in_child_group("PIA", &["SG4"], sg4_idx, "SG8", sg8_idx);
                let has_qualifying_pia = pias.iter().any(|s| {
                    s.elements
                        .first()
                        .and_then(|e: &Vec<String>| e.first())
                        .is_some_and(|v: &String| v == "Z02")
                        && s.elements
                            .get(1)
                            .and_then(|e: &Vec<String>| e.first())
                            .map(|code| {
                                code.starts_with("1-08-1")
                                    || code.starts_with("1-08-2")
                                    || code.starts_with("1-08-3")
                                    || code.starts_with("1-08-4")
                                    || code.starts_with("1-08-5")
                            })
                            .unwrap_or(false)
                });
                if has_qualifying_pia {
                    *count_by_zid.entry(zid).or_insert(0) += 1;
                }
            }
        }
        ConditionResult::from(count_by_zid.values().any(|&c| c > 1))
    }

