    // REVIEW: Scans segments linearly to collect RFF+MG device IDs from each SG8 group with SEQ+Z20 (OBIS-Daten der Zähleinrichtung/Smartmeter-Gateway). A new SEQ starts a new SG8 context; RFF+MG within that context records the device number. Returns True if any device ID appears in 2+ different SG8 groups (indicating multiple OBIS datasets reference the same device). Linear scan is used because the navigator API does not expose a direct method to retrieve segments within a parent SG8 instance by absolute index. (medium confidence)
    fn evaluate_123(&self, ctx: &EvaluationContext) -> ConditionResult {
        struct Sg8Z20Entry {
            mg_id: Option<String>,
        }
        let mut entries: Vec<Sg8Z20Entry> = Vec::new();
        let mut current: Option<Sg8Z20Entry> = None;
        for seg in ctx.segments {
            match seg.id.as_str() {
                "SEQ" => {
                    if let Some(entry) = current.take() {
                        entries.push(entry);
                    }
                    if seg
                        .elements
                        .first()
                        .and_then(|e: &Vec<String>| e.first())
                        .is_some_and(|v: &String| v == "Z20")
                    {
                        current = Some(Sg8Z20Entry { mg_id: None });
                    }
                }
                "RFF" if current.is_some() => {
                    if seg
                        .elements
                        .first()
                        .and_then(|e: &Vec<String>| e.first())
                        .is_some_and(|v: &String| v == "MG")
                    {
                        if let Some(ref mut entry) = current {
                            if entry.mg_id.is_none() {
                                entry.mg_id = seg.elements.first().and_then(|e| e.get(1)).cloned();
                            }
                        }
                    }
                }
                _ => {}
            }
        }
        if let Some(entry) = current {
            entries.push(entry);
        }
        let ids: Vec<&str> = entries
            .iter()
            .filter_map(|e| e.mg_id.as_deref().filter(|s| !s.is_empty()))
            .collect();
        for i in 0..ids.len() {
            for j in (i + 1)..ids.len() {
                if ids[i] == ids[j] {
                    return ConditionResult::True;
                }
            }
        }
        ConditionResult::False
    }

