    /// [132] Wenn dieses DTM+Z25 (Verwendung der Daten ab) im SG6 RFF (Verwendungszeitraum der Daten) mit der Zeitraum ID "1" im DE1156 gekennzeichnet ist, muss das Datum in diesem DE2380 der direkt auf DTM+137...
    // REVIEW: Validates that when RFF in SG6 has Zeitraum-ID '1' (elements[0][2] = DE1156), the DTM+Z25 date must equal the day immediately following DTM+137 (Nachrichtendatum) at 00:00. Parses the YYYYMMDD portion of DTM+137, computes next calendar day with correct month/year rollover, then checks that DTM+Z25's first 12 characters match YYYYMMDDHHMM with HHMM=0000. Note: German timezone offset (CET/CEST) validation is not performed — this checks the stored datetime value directly, which is the common encoding in EDIFACT 303 format for this use case. (medium confidence)
    fn evaluate_132(&self, ctx: &EvaluationContext) -> ConditionResult {
        // Condition applies only when RFF in SG6 has Zeitraum-ID "1" in DE1156 (elements[0][2])
        let has_zeitraum_id_1 = ctx.find_segments("RFF").iter().any(|s| {
            s.elements
                .first()
                .and_then(|e| e.get(2))
                .is_some_and(|v: &String| v == "1")
        });
        if !has_zeitraum_id_1 {
            return ConditionResult::False;
        }
        // Get message date from DTM+137 (format 303: CCYYMMDDHHmm...)
        let msg_date_str = match ctx
            .find_segments_with_qualifier("DTM", 0, "137")
            .into_iter()
            .next()
        {
            Some(seg) => match seg.elements.first().and_then(|e| e.get(1)) {
                Some(v) if v.len() >= 8 => v.clone(),
                _ => return ConditionResult::Unknown,
            },
            None => return ConditionResult::Unknown,
        };
        // Get DTM+Z25 (Verwendung der Daten ab) value
        let usage_date_str = match ctx
            .find_segments_with_qualifier("DTM", 0, "Z25")
            .into_iter()
            .next()
        {
            Some(seg) => match seg.elements.first().and_then(|e| e.get(1)) {
                Some(v) if v.len() >= 12 => v.clone(),
                _ => return ConditionResult::Unknown,
            },
            None => return ConditionResult::Unknown,
        };
        // Parse YYYYMMDD from DTM+137 value
        let year: u32 = match msg_date_str[..4].parse() {
            Ok(v) => v,
            Err(_) => return ConditionResult::Unknown,
        };
        let month: u32 = match msg_date_str[4..6].parse() {
            Ok(v) => v,
            Err(_) => return ConditionResult::Unknown,
        };
        let day: u32 = match msg_date_str[6..8].parse() {
            Ok(v) => v,
            Err(_) => return ConditionResult::Unknown,
        };
        let days_in_month: u32 = match month {
            1 | 3 | 5 | 7 | 8 | 10 | 12 => 31,
            4 | 6 | 9 | 11 => 30,
            2 => {
                if year % 4 == 0 && (year % 100 != 0 || year % 400 == 0) {
                    29
                } else {
                    28
                }
            }
            _ => return ConditionResult::Unknown,
        };
        let (next_year, next_month, next_day): (u32, u32, u32) = if day >= days_in_month {
            if month == 12 {
                (year + 1, 1, 1)
            } else {
                (year, month + 1, 1)
            }
        } else {
            (year, month, day + 1)
        };
        // Expected DTM+Z25: next day at 00:00 — format 303 prefix YYYYMMDDHHMM = 12 chars
        let expected_prefix = format!("{:04}{:02}{:02}0000", next_year, next_month, next_day);
        let actual_len = usage_date_str.len().min(12);
        let actual_prefix = &usage_date_str[..actual_len];
        ConditionResult::from(actual_prefix == expected_prefix.as_str())
    }

