    /// [149] Wenn zwei SG8 SEQ+Z45 (Netznutzungsabrechnungsdaten der Marktlokation), mit  derselben Zeitraum-ID im DE1050, mit Artikel-ID im SG8 PIA+Z02 (Gruppenartikel-ID / Artikel-ID), eine SG8 mit 1-02-0-017...
    // REVIEW: Condition checks whether two SG8 SEQ+Z45 groups with the same Zeitraum-ID (elements[1][0]) each contain PIA+Z02 (DE4347=Z02) with product codes '1-02-0-017' and '1-02-0-018'. Uses collect_group_values to gather SEQ qualifiers and Zeitraum-IDs per group instance, then PIA qualifiers and product codes (elements[1][0]=DE7140) per group instance. Positional alignment of pia_quals and pia_prods (both from same PIA segments in same order) enables reliable qualifier-to-product matching. Groups product codes by Zeitraum-ID to check co-occurrence. (medium confidence)
    fn evaluate_149(&self, ctx: &EvaluationContext) -> ConditionResult {
        use std::collections::{HashMap, HashSet};
        let seq_quals = ctx.collect_group_values("SEQ", 0, 0, &["SG4", "SG8"]);
        let seq_zeitraum = ctx.collect_group_values("SEQ", 1, 0, &["SG4", "SG8"]);
        let pia_quals = ctx.collect_group_values("PIA", 0, 0, &["SG4", "SG8"]);
        let pia_prods = ctx.collect_group_values("PIA", 1, 0, &["SG4", "SG8"]);
        // Map group index -> Zeitraum-ID for SG8s with SEQ+Z45
        let mut idx_to_zeitraum: HashMap<usize, String> = HashMap::new();
        for ((gi, q), (_, zid)) in seq_quals.iter().zip(seq_zeitraum.iter()) {
            if q == "Z45" && !zid.is_empty() {
                idx_to_zeitraum.insert(*gi, zid.clone());
            }
        }
        if idx_to_zeitraum.is_empty() {
            return ConditionResult::False;
        }
        // Map Zeitraum-ID -> set of PIA+Z02 product codes found in the same SG8 group
        let mut zeitraum_products: HashMap<String, HashSet<String>> = HashMap::new();
        for (i, (gi, qual)) in pia_quals.iter().enumerate() {
            if qual == "Z02" {
                if let Some(zid) = idx_to_zeitraum.get(gi) {
                    if let Some((_, prod)) = pia_prods.get(i) {
                        if !prod.is_empty() {
                            zeitraum_products
                                .entry(zid.clone())
                                .or_default()
                                .insert(prod.clone());
                        }
                    }
                }
            }
        }
        ConditionResult::from(
            zeitraum_products
                .values()
                .any(|codes| codes.contains("1-02-0-017") && codes.contains("1-02-0-018")),
        )
    }

