    /// [173] Wenn im RFF+Z33 (Referenz auf den Objektcode in der Lokationsbündelstruktur) das DE1156 (Fortlaufende Nummer eines Lokationsbündels im Geschäftsvorfall) in derselben SG8 SEQ+Z58/ ZC9/ ZD0/ ZD6 (...
    // REVIEW: Condition is True when, in an SG8 with SEQ+Z58/ZC9/ZD0/ZD6 (Zuordnung Lokation zum Objektcode), RFF+Z33 exists but its DE1156 (elements[0][2] = Fortlaufende Nummer) is absent or empty. Uses collect_group_values to find target SG8 group indices by SEQ qualifier, then positionally aligns rff_quals[i] with rff_de1156[i] (same RFF segment) to check DE1156 emptiness scoped to those groups. Returns Unknown if no RFF+Z33 found in target groups (condition not applicable), False if all RFF+Z33 have DE1156 present. (medium confidence)
    fn evaluate_173(&self, ctx: &EvaluationContext) -> ConditionResult {
        use std::collections::HashSet;
        let seq_quals = ctx.collect_group_values("SEQ", 0, 0, &["SG4", "SG8"]);
        let target_indices: HashSet<usize> = seq_quals
            .iter()
            .filter(|(_, q)| matches!(q.as_str(), "Z58" | "ZC9" | "ZD0" | "ZD6"))
            .map(|(i, _)| *i)
            .collect();
        if target_indices.is_empty() {
            return ConditionResult::Unknown;
        }
        // Collect RFF qualifier (elements[0][0]) and DE1156 (elements[0][2]) with positional alignment
        let rff_quals = ctx.collect_group_values("RFF", 0, 0, &["SG4", "SG8"]);
        let rff_de1156 = ctx.collect_group_values("RFF", 0, 2, &["SG4", "SG8"]);
        let mut found_rff_z33 = false;
        for (i, (gi, qual)) in rff_quals.iter().enumerate() {
            if qual == "Z33" && target_indices.contains(gi) {
                found_rff_z33 = true;
                let de1156_empty = rff_de1156.get(i).map(|(_, v)| v.is_empty()).unwrap_or(true);
                if de1156_empty {
                    return ConditionResult::True;
                }
            }
        }
        if found_rff_z33 {
            ConditionResult::False
        } else {
            ConditionResult::Unknown
        }
    }

