    /// [196] Wenn der Objektcode im RFF+Z33 (Referenz auf den Objektcode in der Lokationsbündelstruktur) im DE1154 derselben SG8 SEQ+Z58/ZC9/ZD0 (Zuordnung Lokation zum Objektcode des Lokationsbündels) in ein...
    // REVIEW: Extended cross-SG8 check vs 175: now requires matching SEQ qualifier code (DE1229), Zeitraum-ID from SEQ DE1050 (elements[1][0]), Objektcode (RFF+Z33 DE1154), AND fortlaufende Nummer (RFF+Z33 DE1156) to all be identical between two distinct SG8 instances. SEQ qualifiers are Z58/ZC9/ZD0 per schema. (medium confidence)
    fn evaluate_196(&self, ctx: &EvaluationContext) -> ConditionResult {
        let nav = match ctx.navigator {
            Some(n) => n,
            None => return ConditionResult::Unknown,
        };
        let sg8_count = nav.group_instance_count(&["SG4", "SG8"]);
        let mut entries: Vec<(usize, String, String, String, String)> = Vec::new();
        for i in 0..sg8_count {
            let seqs = nav.find_segments_in_group("SEQ", &["SG4", "SG8"], i);
            let seq_opt = seqs.iter().find(|s| {
                s.elements
                    .first()
                    .and_then(|e: &Vec<String>| e.first())
                    .is_some_and(|v: &String| matches!(v.as_str(), "Z58" | "ZC9" | "ZD0"))
            });
            let seq = match seq_opt {
                Some(s) => s,
                None => continue,
            };
            let seq_code = seq
                .elements
                .first()
                .and_then(|e: &Vec<String>| e.first())
                .cloned()
                .unwrap_or_default();
            let zeitraum_id = seq
                .elements
                .get(1)
                .and_then(|e: &Vec<String>| e.first())
                .cloned()
                .unwrap_or_default();
            let rffs = nav.find_segments_in_group("RFF", &["SG4", "SG8"], i);
            for rff in &rffs {
                let elems = match rff.elements.first() {
                    Some(e) => e,
                    None => continue,
                };
                if elems.first().map(|s| s.as_str()) != Some("Z33") {
                    continue;
                }
                let objektcode = elems.get(1).cloned().unwrap_or_default();
                let fort_nr = elems.get(2).cloned().unwrap_or_default();
                if !objektcode.is_empty() {
                    entries.push((
                        i,
                        seq_code.clone(),
                        zeitraum_id.clone(),
                        objektcode,
                        fort_nr,
                    ));
                }
            }
        }
        for a in 0..entries.len() {
            for b in (a + 1)..entries.len() {
                if entries[a].0 != entries[b].0
                    && entries[a].1 == entries[b].1
                    && entries[a].2 == entries[b].2
                    && entries[a].3 == entries[b].3
                    && entries[a].4 == entries[b].4
                {
                    return ConditionResult::True;
                }
            }
        }
        ConditionResult::False
    }

    /// [197] Wenn das RFF+Z18 (Marktlokation) aus dieser SG8 auf das gleiche SG5 LOC+Z16 (Marktlokation), wie ein RFF+Z18 (Marktlokation) aus einer SG8 SEQ+Z01 (Daten der Marktlokation), in dem SG10 CCI+++ZA6 (...
    // REVIEW: Two-phase cross-SG8 check. Phase 1: collect Marktlokation IDs from SG8 instances that (a) have SEQ+Z01 and (b) have an SG10 child with CCI elements[2][0]=ZA6 and CAV elements[0][0]=E02. Phase 2: check whether any SG8's RFF+Z18 references one of those qualifying Marktlokation IDs, establishing the cross-reference described in the condition. (medium confidence)
    fn evaluate_197(&self, ctx: &EvaluationContext) -> ConditionResult {
        let nav = match ctx.navigator {
            Some(n) => n,
            None => return ConditionResult::Unknown,
        };
        let sg8_count = nav.group_instance_count(&["SG4", "SG8"]);
        let mut qualifying_malo_ids: Vec<String> = Vec::new();
        for i in 0..sg8_count {
            let seqs = nav.find_segments_in_group("SEQ", &["SG4", "SG8"], i);
            if !seqs.iter().any(|s| {
                s.elements
                    .first()
                    .and_then(|e: &Vec<String>| e.first())
                    .is_some_and(|v: &String| v == "Z01")
            }) {
                continue;
            }
            let sg10_count = nav.child_group_instance_count(&["SG4", "SG8"], i, "SG10");
            let has_prog = (0..sg10_count).any(|j| {
                let ccis = nav.find_segments_in_child_group("CCI", &["SG4", "SG8"], i, "SG10", j);
                let has_za6 = ccis.iter().any(|s| {
                    s.elements
                        .get(2)
                        .and_then(|e: &Vec<String>| e.first())
                        .is_some_and(|v: &String| v == "ZA6")
                });
                if !has_za6 {
                    return false;
                }
                let cavs = nav.find_segments_in_child_group("CAV", &["SG4", "SG8"], i, "SG10", j);
                cavs.iter().any(|s| {
                    s.elements
                        .first()
                        .and_then(|e: &Vec<String>| e.first())
                        .is_some_and(|v: &String| v == "E02")
                })
            });
            if !has_prog {
                continue;
            }
            let rffs = nav.find_segments_in_group("RFF", &["SG4", "SG8"], i);
            for rff in &rffs {
                let elems = match rff.elements.first() {
                    Some(e) => e,
                    None => continue,
                };
                if elems.first().map(|s| s.as_str()) != Some("Z18") {
                    continue;
                }
                if let Some(malo_id) = elems.get(1) {
                    if !malo_id.is_empty() {
                        qualifying_malo_ids.push(malo_id.clone());
                    }
                }
            }
        }
        if qualifying_malo_ids.is_empty() {
            return ConditionResult::False;
        }
        for i in 0..sg8_count {
            let rffs = nav.find_segments_in_group("RFF", &["SG4", "SG8"], i);
            for rff in &rffs {
                let elems = match rff.elements.first() {
                    Some(e) => e,
                    None => continue,
                };
                if elems.first().map(|s| s.as_str()) != Some("Z18") {
                    continue;
                }
                if let Some(malo_id) = elems.get(1) {
                    if qualifying_malo_ids.contains(malo_id) {
                        return ConditionResult::True;
                    }
                }
            }
        }
        ConditionResult::False
    }

