    /// [202] Wenn SG8 SEQ+Z78 RFF+Z39 (Keine standardisierte Lokationsbündelstruktur vorhanden), mit identischer Zeitraum-ID im DE1050 wie im DE3224 dieses Segments
    // REVIEW: Collects Zeitraum-IDs from SG5 LOC.DE3224 (elements[1][3]), checks SEQ+Z78 DE1050 (elements[1][0]) for a match, then verifies RFF+Z39 exists. Co-occurrence of SEQ+Z78 and RFF+Z39 in the same SG8 instance is not verified without navigator group-instance access. (medium confidence)
    fn evaluate_202(&self, ctx: &EvaluationContext) -> ConditionResult {
        use std::collections::HashSet;
        // Collect Zeitraum-IDs from all SG5 LOC segments (DE3224 at elements[1][3])
        let loc_zeitraum_ids: HashSet<String> = ctx
            .find_segments("LOC")
            .into_iter()
            .filter_map(|s| s.elements.get(1)?.get(3).cloned())
            .filter(|v| !v.is_empty())
            .collect();
        if loc_zeitraum_ids.is_empty() {
            return ConditionResult::False;
        }
        // Check if any SEQ+Z78 (SG8 Lokationsbündelstruktur) has DE1050 matching a LOC DE3224
        let matching_seq = ctx
            .find_segments_with_qualifier("SEQ", 0, "Z78")
            .into_iter()
            .any(|s| {
                s.elements
                    .get(1)
                    .and_then(|e: &Vec<String>| e.first())
                    .is_some_and(|v: &String| {
                        !v.is_empty() && loc_zeitraum_ids.contains(v.as_str())
                    })
            });
        if !matching_seq {
            return ConditionResult::False;
        }
        // Verify RFF+Z39 also exists (co-occurrence in same SG8 not verified without navigator)
        ctx.has_qualifier("RFF", 0, "Z39")
    }

