    /// [229] Wenn der Objektcode im RFF+Z33 (Referenz auf den Objektcode in der Lokationsbündelstruktur) im DE1154 derselben SG8 SEQ+Z58/ ZC9/ ZD0/ ZD6 (Zuordnung Lokation zum Objektcode des Lokationsbündels)...
    // REVIEW: Detects if the same (SEQ-qualifier, Zeitraum-ID, RFF+Z33-Objektcode) triple appears in two different SG8 instances — which is what the condition guards against. Uses collect_group_values to correlate SEQ and RFF data by SG8 instance index. Limitation: collect_group_values may only return the first RFF per SG8 instance, so Z33 may be missed if it is not the first RFF in the group. (medium confidence)
    fn evaluate_229(&self, ctx: &EvaluationContext) -> ConditionResult {
        use std::collections::HashSet;
        let target_quals: HashSet<&str> = ["Z58", "ZC9", "ZD0", "ZD6"].iter().cloned().collect();
        // Collect per-SG8-instance: SEQ qualifier and Zeitraum-ID
        let seq_quals = ctx.collect_group_values("SEQ", 0, 0, &["SG4", "SG8"]);
        let seq_zeitraums = ctx.collect_group_values("SEQ", 1, 0, &["SG4", "SG8"]);
        // Collect per-SG8-instance: RFF qualifier and DE1154 value
        let rff_quals = ctx.collect_group_values("RFF", 0, 0, &["SG4", "SG8"]);
        let rff_codes = ctx.collect_group_values("RFF", 0, 1, &["SG4", "SG8"]);
        // Detect duplicate (seq_qual, zeitraum_id, objektcode) combinations across SG8 instances
        let mut seen: HashSet<(String, String, String)> = HashSet::new();
        for (idx, seq_qual) in &seq_quals {
            if seq_qual.is_empty() || !target_quals.contains(seq_qual.as_str()) {
                continue;
            }
            let zeitraum_id = seq_zeitraums
                .iter()
                .find(|(i, _)| i == idx)
                .map(|(_, v)| v.as_str())
                .unwrap_or("");
            // Find RFF+Z33 in this SG8 instance (correlation by instance index)
            for (ridx, rff_qual) in rff_quals.iter() {
                if ridx != idx || rff_qual != "Z33" {
                    continue;
                }
                if let Some((_, obj_code)) = rff_codes.iter().find(|(i, _)| i == ridx) {
                    if obj_code.is_empty() {
                        continue;
                    }
                    let key = (seq_qual.clone(), zeitraum_id.to_string(), obj_code.clone());
                    if seen.contains(&key) {
                        return ConditionResult::True;
                    }
                    seen.insert(key);
                }
            }
        }
        ConditionResult::False
    }

