    /// [327] Wenn die Zeitraum-ID im DE1050 dieser SG8 SEQ, welche mit der Zeitraum-ID einer SG6 RFF+Z47/Z48/Z49 (Verwendungszeitraum der Daten) identisch ist und in deren SG das SG6 DTM+Z25 (Verwendung der Dat...
    // REVIEW: Step 1: Collect all SEQ DE1050 Zeitraum-IDs. Step 2: Find RFF+Z47/Z48/Z49 (Verwendungszeitraum) whose DE1156 (elements[0][2]) matches. Step 3: Check co-located DTM+Z25 DE2380 (elements[0][1]) >= threshold after normalising EDIFACT escape '?+' to '+'. Falls back to message-wide DTM search which may give false positives if multiple SG6 groups are present, but is sufficient for typical single-transaction messages. (medium confidence)
    fn evaluate_327(&self, ctx: &EvaluationContext) -> ConditionResult {
        const THRESHOLD: &str = "202212312300+00";
        let seq_zeitraum_ids: Vec<String> = ctx
            .find_segments("SEQ")
            .iter()
            .filter_map(|s| {
                s.elements
                    .get(1)
                    .and_then(|e: &Vec<String>| e.first())
                    .cloned()
            })
            .filter(|v| !v.is_empty())
            .collect();
        if seq_zeitraum_ids.is_empty() {
            return ConditionResult::Unknown;
        }
        let rff_segs = ctx.find_segments("RFF");
        let matching_rff = rff_segs.iter().any(|rff| {
            let qual = rff
                .elements
                .first()
                .and_then(|e: &Vec<String>| e.first())
                .map(|v| v.as_str())
                .unwrap_or("");
            if !["Z47", "Z48", "Z49"].contains(&qual) {
                return false;
            }
            let zid = rff
                .elements
                .first()
                .and_then(|e| e.get(2))
                .map(|v| v.as_str())
                .unwrap_or("");
            !zid.is_empty() && seq_zeitraum_ids.iter().any(|id| id.as_str() == zid)
        });
        if !matching_rff {
            return ConditionResult::False;
        }
        for dtm in ctx.find_segments_with_qualifier("DTM", 0, "Z25") {
            let val = dtm
                .elements
                .first()
                .and_then(|e| e.get(1))
                .map(|v| v.replace("?+", "+"))
                .unwrap_or_default();
            if !val.is_empty() && val.as_str() >= THRESHOLD {
                return ConditionResult::True;
            }
        }
        ConditionResult::False
    }

