    // REVIEW: Checks whether any SG8 instance lacks CCI+6++ZA9 (Aggregationsverantwortung ÜNB, elements[0]='6' and elements[2][0]='ZA9') in its SG10 children. With navigator: iterates SG8 instances and their SG10 children. Without navigator: falls back to message-wide CCI+6 with ZA9 check. The Zeitraum-ID cross-reference between this SG8 and the Z01 SG8 cannot be fully verified without direct SG8-level segment access via navigator, so this is an approximation that may produce false positives in multi-SG4-group messages. (medium confidence)
    fn evaluate_332(&self, ctx: &EvaluationContext) -> ConditionResult {
        let nav = match ctx.navigator {
            Some(n) => n,
            None => {
                if ctx.find_segments_with_qualifier("SEQ", 0, "Z01").is_empty() {
                    return ConditionResult::Unknown;
                }
                let has_cci_za9 = ctx
                    .find_segments_with_qualifier("CCI", 0, "6")
                    .iter()
                    .any(|s| {
                        s.elements
                            .get(2)
                            .and_then(|e: &Vec<String>| e.first())
                            .map(|v| v.as_str())
                            == Some("ZA9")
                    });
                return ConditionResult::from(!has_cci_za9);
            }
        };
        let sg8_count = nav.group_instance_count(&["SG4", "SG8"]);
        if sg8_count == 0 {
            return ConditionResult::Unknown;
        }
        for sg8_idx in 0..sg8_count {
            let sg10_count = nav.child_group_instance_count(&["SG4", "SG8"], sg8_idx, "SG10");
            let mut has_cci_za9 = false;
            for sg10_idx in 0..sg10_count {
                let ccis = nav.find_segments_in_child_group(
                    "CCI",
                    &["SG4", "SG8"],
                    sg8_idx,
                    "SG10",
                    sg10_idx,
                );
                if ccis.iter().any(|s| {
                    s.elements
                        .first()
                        .and_then(|e: &Vec<String>| e.first())
                        .map(|v| v.as_str())
                        == Some("6")
                        && s.elements
                            .get(2)
                            .and_then(|e: &Vec<String>| e.first())
                            .map(|v| v.as_str())
                            == Some("ZA9")
                }) {
                    has_cci_za9 = true;
                    break;
                }
            }
            if !has_cci_za9 {
                return ConditionResult::True;
            }
        }
        ConditionResult::False
    }

