    /// [403] Wenn nicht dieselbe MP-ID in SG2 NAD+MS (Nachrichtensender) und im SG8 SEQ+Z01 (Daten der Marktlokation) SG10 CCI+++ZB3 (Zugeordnete Marktpartner) CAV+Z91 (Messtellenbetreiber) vorhanden
    // REVIEW: Gets NAD+MS MP-ID from SG2 (elements[1][0]), then navigates all SG8→SG10 instances looking for CCI with elements[2][0]='ZB3' (Zugeordnete Marktpartner) and CAV with elements[0][0]='Z91' (Messstellenbetreiber). Compares the CAV+Z91 MP-ID (elements[0][1]) with the sender MP-ID. Returns True when they differ (not the same). Note: SEQ+Z01 filter on the parent SG8 is omitted because `find_segments_in_child_group` only accesses child groups, not the parent SG8 segments; the Z91 MSB identity is message-consistent regardless. (medium confidence)
    fn evaluate_403(&self, ctx: &EvaluationContext) -> ConditionResult {
        let sender_mp_id: String = match ctx.find_segments_with_qualifier("NAD", 0, "MS").first() {
            Some(nad) => match nad.elements.get(1).and_then(|e: &Vec<String>| e.first()) {
                Some(id) if !id.is_empty() => id.clone(),
                _ => return ConditionResult::Unknown,
            },
            None => return ConditionResult::Unknown,
        };
        let nav = match ctx.navigator {
            Some(n) => n,
            None => return ConditionResult::Unknown,
        };
        let sg8_count = nav.group_instance_count(&["SG4", "SG8"]);
        for i in 0..sg8_count {
            let sg10_count = nav.child_group_instance_count(&["SG4", "SG8"], i, "SG10");
            for j in 0..sg10_count {
                let ccis = nav.find_segments_in_child_group("CCI", &["SG4", "SG8"], i, "SG10", j);
                let has_cci_zb3 = ccis.iter().any(|s| {
                    s.elements
                        .get(2)
                        .and_then(|e: &Vec<String>| e.first())
                        .is_some_and(|v: &String| v == "ZB3")
                });
                if !has_cci_zb3 {
                    continue;
                }
                let cavs = nav.find_segments_in_child_group("CAV", &["SG4", "SG8"], i, "SG10", j);
                for cav in &cavs {
                    if cav
                        .elements
                        .first()
                        .and_then(|e: &Vec<String>| e.first())
                        .is_some_and(|v: &String| v == "Z91")
                    {
                        if let Some(msb_id) = cav.elements.first().and_then(|e| e.get(1)) {
                            if !msb_id.is_empty() {
                                return ConditionResult::from(
                                    sender_mp_id.as_str() != msb_id.as_str(),
                                );
                            }
                        }
                    }
                }
            }
        }
        ConditionResult::Unknown
    }

    /// [404] Wenn nicht dieselbe MP-ID in SG2 NAD+MR (Nachrichtenempfänger) und im SG8 SEQ+Z01/ Z98 (Daten der Marktlokation) SG10 CCI+++ZB3 (Zugeordnete Marktpartner) CAV+Z91 (Messtellenbetreiber) vorhanden
    // REVIEW: Reads NAD+MR MP-ID from elements[1][0], then iterates all SG8 SG10 children looking for CCI with elements[2][0]==ZB3 and CAV with elements[0][0]==Z91 where the MP-ID (elements[0][1]) matches. Returns False if same MP-ID found (condition 'not same' fails), True otherwise. Approximation: cannot filter SG8 instances by SEQ+Z01/Z98 without find_segments_in_group; checks all SG8 SG10 children. This is acceptable since CCI+ZB3 CAV+Z91 patterns in other SG8 types would still represent valid MSB assignments to compare against. (medium confidence)
    fn evaluate_404(&self, ctx: &EvaluationContext) -> ConditionResult {
        let mr_nads = ctx.find_segments_with_qualifier("NAD", 0, "MR");
        let mr_mp_id = match mr_nads.first() {
            Some(nad) => nad
                .elements
                .get(1)
                .and_then(|e: &Vec<String>| e.first())
                .cloned()
                .unwrap_or_default(),
            None => return ConditionResult::Unknown,
        };
        if mr_mp_id.is_empty() {
            return ConditionResult::Unknown;
        }

        let nav = match ctx.navigator {
            Some(n) => n,
            None => {
                let cavs = ctx.find_segments("CAV");
                let same_id_exists = cavs.iter().any(|s| {
                    s.elements
                        .first()
                        .and_then(|e: &Vec<String>| e.first())
                        .is_some_and(|v: &String| v == "Z91")
                        && s.elements
                            .first()
                            .and_then(|e| e.get(1))
                            .is_some_and(|v: &String| v == &mr_mp_id)
                });
                return ConditionResult::from(!same_id_exists);
            }
        };

        let sg8_count = nav.group_instance_count(&["SG4", "SG8"]);
        for i in 0..sg8_count {
            let sg10_count = nav.child_group_instance_count(&["SG4", "SG8"], i, "SG10");
            for j in 0..sg10_count {
                let ccis = nav.find_segments_in_child_group("CCI", &["SG4", "SG8"], i, "SG10", j);
                let has_cci_zb3 = ccis.iter().any(|s| {
                    s.elements
                        .get(2)
                        .and_then(|e: &Vec<String>| e.first())
                        .is_some_and(|v: &String| v == "ZB3")
                });
                if !has_cci_zb3 {
                    continue;
                }
                let cavs = nav.find_segments_in_child_group("CAV", &["SG4", "SG8"], i, "SG10", j);
                for cav in &cavs {
                    if cav
                        .elements
                        .first()
                        .and_then(|e: &Vec<String>| e.first())
                        .is_some_and(|v: &String| v == "Z91")
                    {
                        let cav_mp_id = cav
                            .elements
                            .first()
                            .and_then(|e| e.get(1))
                            .map(|s| s.as_str())
                            .unwrap_or("");
                        if cav_mp_id == mr_mp_id.as_str() {
                            return ConditionResult::False;
                        }
                    }
                }
            }
        }

        ConditionResult::True
    }

