    /// [444] Wenn in derselben SG8 (Produkt-Daten der Netzlokation) das PIA+5 (Produkt-Daten der Netzlokation) nicht vorhanden
    // REVIEW: Checks whether any SG8 instance carrying a 'Produkt-Daten der Netzlokation' SEQ qualifier (Z60, ZE0, ZG8, ZG9) lacks PIA+5. Iterates each qualifier separately using any_group_has_qualifier_without which checks: SEQ+code present AND PIA+5 absent in same SG8. Returns True on first match. Correctly handles the multi-qualifier case via OR iteration. (medium confidence)
    fn evaluate_444(&self, ctx: &EvaluationContext) -> ConditionResult {
        for code in ["Z60", "ZE0", "ZG8", "ZG9"] {
            if matches!(
                ctx.any_group_has_qualifier_without("SEQ", 0, code, "PIA", 0, "5", &["SG4", "SG8"]),
                ConditionResult::True
            ) {
                return ConditionResult::True;
            }
        }
        ConditionResult::False
    }

    /// [445] Wenn in derselben SG8 (Produkt-Daten der Netzlokation) das SG10 CCI+11 (Details zum Produkt der Netzlokation) nicht vorhanden
    // REVIEW: Iterates all SG8 instances and checks whether any SG10 child group contains CCI with elements[0][0]=="11" (Details zum Produkt der Netzlokation). Returns True when an SG8 is found that lacks such a CCI+11 in its SG10 children. Navigator fallback uses filtered_parent_child_has_qualifier negated per qualifier. Approximation: the navigator path does not filter SG8 instances by Produkt-Daten-Netzlokation SEQ qualifier due to absence of find_segments_in_group; checks all SG8 instances instead. (medium confidence)
    fn evaluate_445(&self, ctx: &EvaluationContext) -> ConditionResult {
        let nav = match ctx.navigator {
            Some(n) => n,
            None => {
                let has_cci11 = ["Z60", "ZE0", "ZG8", "ZG9"].iter().any(|code| {
                    matches!(
                        ctx.filtered_parent_child_has_qualifier(
                            &["SG4", "SG8"],
                            "SEQ",
                            0,
                            code,
                            "SG10",
                            "CCI",
                            0,
                            "11",
                        ),
                        ConditionResult::True
                    )
                });
                return ConditionResult::from(!has_cci11);
            }
        };

        let sg8_count = nav.group_instance_count(&["SG4", "SG8"]);
        for i in 0..sg8_count {
            let sg10_count = nav.child_group_instance_count(&["SG4", "SG8"], i, "SG10");
            let has_cci11 = (0..sg10_count).any(|j| {
                let ccis = nav.find_segments_in_child_group("CCI", &["SG4", "SG8"], i, "SG10", j);
                ccis.iter().any(|s| {
                    s.elements
                        .first()
                        .and_then(|e: &Vec<String>| e.first())
                        .is_some_and(|v: &String| v == "11")
                })
            });
            if !has_cci11 {
                return ConditionResult::True;
            }
        }
        ConditionResult::False
    }

