    /// [2004] Segmentgruppe ist genau einmal für jede Zeitraum-ID aus dem DE1156 der SG6 RFF+Z49 (Verwendungszeitraum der Daten: "Gültige Daten") anzugeben
    // REVIEW: Collects Zeitraum-IDs from SG6 RFF+Z49 DE1156 (elements[0][2]) by correlating qualifier (elements[0][0]) and ID (elements[0][2]) vectors via shared SG6 instance index. Then collects all SEQ DE1050 (elements[1][0]) references from SG8 instances. For each Zeitraum-ID from SG6 RFF+Z49, counts matching SG8 SEQ references; returns False if any count != 1 (violates 'exactly once' cardinality). Returns Unknown if no RFF+Z49 Zeitraum-IDs exist. (medium confidence)
    fn evaluate_2004(&self, ctx: &EvaluationContext) -> ConditionResult {
        let rff_qualifiers = ctx.collect_group_values("RFF", 0, 0, &["SG4", "SG6"]);
        let rff_zeitraum_ids = ctx.collect_group_values("RFF", 0, 2, &["SG4", "SG6"]);

        let zeitraum_ids: Vec<String> = rff_qualifiers
            .iter()
            .filter(|(_, qual)| qual.as_str() == "Z49")
            .filter_map(|(idx, _)| {
                rff_zeitraum_ids
                    .iter()
                    .find(|(i, v)| i == idx && !v.is_empty())
                    .map(|(_, v)| v.clone())
            })
            .collect();

        if zeitraum_ids.is_empty() {
            return ConditionResult::Unknown;
        }

        let seq_refs = ctx.collect_group_values("SEQ", 1, 0, &["SG4", "SG8"]);

        for zid in &zeitraum_ids {
            let count = seq_refs.iter().filter(|(_, v)| v == zid).count();
            if count != 1 {
                return ConditionResult::False;
            }
        }

        ConditionResult::True
    }

    /// [2005] Segmentgruppe ist mindesten einmal für jede Zeitraum-ID aus dem DE1156 der SG6 RFF+Z49 (Verwendungszeitraum der Daten: "Gültige Daten") anzugeben
    // REVIEW: Same logic as 2004 but enforces 'at least once' cardinality (count >= 1) instead of 'exactly once'. Collects Zeitraum-IDs from SG6 RFF+Z49 DE1156 and checks that each has at least one matching SG8 SEQ DE1050 reference. Returns False if any Zeitraum-ID has zero matching SG8 references. (medium confidence)
    fn evaluate_2005(&self, ctx: &EvaluationContext) -> ConditionResult {
        let rff_qualifiers = ctx.collect_group_values("RFF", 0, 0, &["SG4", "SG6"]);
        let rff_zeitraum_ids = ctx.collect_group_values("RFF", 0, 2, &["SG4", "SG6"]);

        let zeitraum_ids: Vec<String> = rff_qualifiers
            .iter()
            .filter(|(_, qual)| qual.as_str() == "Z49")
            .filter_map(|(idx, _)| {
                rff_zeitraum_ids
                    .iter()
                    .find(|(i, v)| i == idx && !v.is_empty())
                    .map(|(_, v)| v.clone())
            })
            .collect();

        if zeitraum_ids.is_empty() {
            return ConditionResult::Unknown;
        }

        let seq_refs = ctx.collect_group_values("SEQ", 1, 0, &["SG4", "SG8"]);

        for zid in &zeitraum_ids {
            let count = seq_refs.iter().filter(|(_, v)| v == zid).count();
            if count == 0 {
                return ConditionResult::False;
            }
        }

        ConditionResult::True
    }

